MAP 
#
#< Start of map file - created 2011-05-07 - 21:22:22
#
NAME 'CATBR_PLANOPREDIAL_UBICACION'
STATUS ON

PROJECTION
			'init=epsg:32720'     # UTM 20, Zona 20S, WGS 1984
END

SIZE 1200 1200
EXTENT 423000 8086700 425500 8089200
UNITS  meters
SYMBOLSET 'c:/apache2/cat_br/mapa/symbols/symbset.sym'
FONTSET   'c:/apache2/cat_br/mapa/fonts/fonts.fnt'
IMAGECOLOR 255 255 255

#
# Start of web interface definition
#
WEB
 LOG cat_br.log
 TEMPLATE catbr_planocatastral_ubicacion.html
 IMAGEPATH 'c:/apache2/htdocs/tmp/'
 IMAGEURL 'http://localhost/tmp/'
 EMPTY 'http://localhost/catastro_br/nada.html'
 
 METADATA
  WMS_ONLINERESOURCE 'http://localhost/cgi-bin/mapserv.exe?map=c:/apache2/cat_br/mapa/catbr_planocatastral_ubicacion.map'
  WMS_SRS 'epsg:32720'
  WMS_ACCESSCONSTRAINTS 'none'
  WMS_TITLE 'CATBR_PLANOCATASTRAL_UBICACION'
  WMS_FEATURE_INFO_MIME_TYPE 'text/html'
  WMS_ABSTRACT ''
 END  #METADATA

END  #HEADER

OUTPUTFORMAT
    NAME 'AGG'
    DRIVER 'AGG/PNG'
    MIMETYPE 'image/png'
    IMAGEMODE RGB
  	FORMATOPTION 'QUALITY=100'		
END

SYMBOL
  NAME 'n_arrow'
  TYPE pixmap
  IMAGE 'C:/apache2/htdocs/catastro_br/graphics/northarrow.png'
	TRANSPARENT 0
END

SYMBOL
   NAME 'circle'
   TYPE ellipse
   FILLED true
   POINTS
     1 1
   END
END

#
# Start of reference map
#
REFERENCE
  STATUS OFF
  IMAGE 'c:/apache2/htdocs/catastro_br/data/reference.gif'
  SIZE 100 100
  EXTENT -70.254 -23.569 -56.844 -8.994
  COLOR -1 -1 -1
  OUTLINECOLOR 255 0 0
END  #REFERENCE

#
# Start of legend
#
LEGEND
  STATUS OFF
  KEYSIZE 16 8
  TEMPLATE 'legend.html'
  LABEL
    COLOR 120 120 120
  END # ENDE LABEL
END   #LEGEND

#
# Start of scalebar
#
SCALEBAR
 STATUS ON
 POSITION ll
 STYLE 0
 INTERVALS 5
 IMAGECOLOR 255 255 255
 LABEL
  COLOR 0 0 0
  SIZE GIANT  #SMALL
 END  #ENDE LABEL
 #SIZE 150 2
 #SIZE 304 4   #Mapsize 700+700
 Size 600 8    #Mapsize 1400+1400
 TRANSPARENT OFF
 COLOR 0 0 0
 BACKGROUNDCOLOR 255 255 255
 OUTLINECOLOR 100 100 100
 UNITS METERS
END   #SCALEBAR

#
# Start of layer definitions #
#
#----------------------------------------------------------- U.V.s
LAYER
  CONNECTIONTYPE postgis
  NAME 'Unidades Vecinales'
  GROUP 'Manzanos'
	CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from manzanos USING UNIQUE oid'
  STATUS ON
  TYPE Polygon
#	TEMPLATE 'query_manzanos.html'
  METADATA
    WMS_SRS 'epsg:32720'
    WMS_TITLE 'Poly'
    WMS_GROUP_TITLE 'Poligono'
    WMS_FEATURE_INFO_MIME_TYPE 'text/html'
  END

PROJECTION
     	'init=epsg:32720'
END

    CLASSITEM 'cod_uv'

      CLASS
       NAME 'U.V.'
			 EXPRESSION /./
			 STYLE
			    SYMBOL 'circle'
          COLOR -1 -1 -1
          OUTLINECOLOR 50 50 50 #40 40 40
			    SIZE 3
			 END
      END  # CLASS
			 
END  # END OF LAYERFILE		
#----------------------------------------------------------- U.V.s
#----------------------------------------------------------- Predios-Outline
LAYER
  CONNECTIONTYPE postgis
  NAME 'predios'
	GROUP 'Predios'
	CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from predios_ocha USING UNIQUE oid'	
  TYPE POLYGON
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'Predios'
 WMS_GROUP_TITLE 'Predios'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

 CLASSITEM 'cod_cat'
	CLASS 
    NAME 'Delimitación'              
		STYLE
		  SYMBOL 'circle'
			#SYMBOL 'Hauptstrasse'
      COLOR -1 -1 -1
      OUTLINECOLOR 0 0 0 #40 40 40			
	    SIZE 1
	  END
	END # end_of_class
END # end of layer object
#----------------------------------------------------------- Predios-Outline
#----------------------------------------------------------- Predio-Seleccionado-Relleno
LAYER
