 WMS_TITLE 'Predio_Select'
 WMS_GROUP_TITLE 'Predios'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

 CLASSITEM 'number'
	CLASS 
    NAME 'Delimitación' 
		EXPRESSION (('[number]' == '55') AND ('[user_id]' == 'AAA'))         
		STYLE
		  SYMBOL 'circle'
      COLOR 150 150 150
      OUTLINECOLOR -1 -1 -1 #40 40 40			
	    SIZE 1
	  END
	END # end_of_class
END # end of layer object
