 CLASSITEM 'number'
	CLASS 
    NAME 'Delimitación' 
		EXPRESSION (('[number]' == '55') AND ('[user_id]' == 'AAA'))         
		STYLE
		  SYMBOL 'circle'
      COLOR -1 -1 -1 #150 150 150
