#----------------------------------------------------------- Calles-Anotation
LAYER 
  CONNECTIONTYPE postgis
  NAME 'Calles_Anot'
	GROUP 'Calles'
	STATUS ON
  CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from calles USING UNIQUE oid'	
  TYPE ANNOTATION

METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'Calles_Anot'
 WMS_GROUP_TITLE 'Calles'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

#MAXSCALE 60000
 CLASSITEM 'id'
 LABELITEM 'nombre'
 
	CLASS 
	 NAME 'Calles'
     EXPRESSION '0' 
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 14
       ANGLE AUTO
       COLOR 0 0 0   # orange: 255 153 51
	#		 OUTLINECOLOR 255 255 255
       BUFFER 2
			 ANTIALIAS TRUE
       POSITION cc
       PARTIALS FALSE
			 FORCE TRUE
      END
  END
END # end of layer object
#----------------------------------------------------------- Calles-Anotation
#----------------------------------------------------------- Manzanos-Anotation
LAYER 
  CONNECTIONTYPE postgis
  NAME 'Manzanos_Anot'
  GROUP 'Manzanos'
	STATUS ON
	CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_poly USING UNIQUE oid'
  TYPE ANNOTATION

METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'Manzanos_Anot'
 WMS_GROUP_TITLE 'Manzanos'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

#MAXSCALE 60000
 CLASSITEM 'number'
 LABELITEM 'label'
 
	CLASS 
	 NAME 'Manzanos'
     EXPRESSION (( '[number]' == '115' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 20
       ANGLE 0
       COLOR 0 0 0   # orange: 255 153 51
	#		 OUTLINECOLOR 255 255 255
       BUFFER 2
			 ANTIALIAS TRUE
       POSITION cc
			 OFFSET 0 -10
       PARTIALS FALSE
			 FORCE FALSE
			 WRAP '@'
      END
  END
END # end of layer object
#----------------------------------------------------------- Manzanos-Anotation
#----------------------------------------------------------- Objetos_Linea
LAYER
  DEBUG ON
  CONNECTIONTYPE postgis 
  NAME 'objetos_linea'
	GROUP 'Calles'
	STATUS ON
  CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from objetos_linea USING UNIQUE oid'
  TYPE LINE
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'objetos_linea'
 WMS_GROUP_TITLE 'Calles'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

 CLASSITEM 'id'
	
	CLASS 
    NAME 'Plaza'
		EXPRESSION '15'             
		STYLE
		  SYMBOL 'linea'
      COLOR 150 150 150
	    SIZE 2
	  END
	END # end_of_class  
	CLASS 
    NAME 'Límite urbáno'
		EXPRESSION '35'               
		STYLE
		  SYMBOL 'linea'
      COLOR 0 0 0
	    SIZE 2
	  END
	END # end_of_class 
